import{_ as e,o as a,c as l,a1 as s}from"./chunks/framework.BX4nIuL2.js";const c=JSON.parse('{"title":"底盘控制链与微处理器集成","description":"","frontmatter":{},"headers":[],"relativePath":"courses/mobile-robot/hardware.md","filePath":"courses/mobile-robot/hardware.md"}'),n={name:"courses/mobile-robot/hardware.md"};function o(i,t,r,d,p,h){return a(),l("div",null,[...t[0]||(t[0]=[s(`<h1 id="底盘控制链与微处理器集成" tabindex="-1">底盘控制链与微处理器集成 <a class="header-anchor" href="#底盘控制链与微处理器集成" aria-label="Permalink to &quot;底盘控制链与微处理器集成&quot;">​</a></h1><p>移动机器人的稳定移动高度依赖底层执行机构（电机、编码器）与控制电路之间的精确配合。本章节详细介绍控制器控制链的硬件搭建。</p><hr><h2 id="_1-电机闭环调速控制链" tabindex="-1">1. 电机闭环调速控制链 <a class="header-anchor" href="#_1-电机闭环调速控制链" aria-label="Permalink to &quot;1. 电机闭环调速控制链&quot;">​</a></h2><p>控制小车速度的核心在于<strong>增量式 PID 闭环算法</strong>，将实测轮转速调节至目标转速。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  +---------+   Target Velocity   +-------------+  PWM Control  +--------------+</span></span>
<span class="line"><span>  |  ROS 2  | ------------------&gt; | MCU / Duo   | ------------&gt; | Motor Driver |</span></span>
<span class="line"><span>  | (上位机) | &lt;------------------ | (底盘控制器) | &lt;------------ |   (H-Bridge) |</span></span>
<span class="line"><span>  +---------+   Odom / feedback   +-------------+ Encoder pulse +--------------+</span></span>
<span class="line"><span>                                         ^</span></span>
<span class="line"><span>                                         |</span></span>
<span class="line"><span>                                         v</span></span>
<span class="line"><span>                                  +-------------+</span></span>
<span class="line"><span>                                  |  PID Loop   |</span></span>
<span class="line"><span>                                  +-------------+</span></span></code></pre></div><h3 id="_1-1-增量式-pid-算法公式" tabindex="-1">1.1 增量式 PID 算法公式 <a class="header-anchor" href="#_1-1-增量式-pid-算法公式" aria-label="Permalink to &quot;1.1 增量式 PID 算法公式&quot;">​</a></h3><p>在底盘微控制器中，每个控制周期（通常为 10ms-20ms）都会计算一次 PWM 占空比输出量：</p><p>$$ \\Delta u(k) = K_p [e(k) - e(k-1)] + K_i e(k) + K_d [e(k) - 2e(k-1) + e(k-2)] $$</p><p>$$ u(k) = u(k-1) + \\Delta u(k) $$</p><ul><li>$e(k)$: 目标脉冲计数与当前周期霍尔编码器实际反馈脉冲计数的差值（速度误差）。</li><li>$u(k)$: 输出到 H 桥芯片的 PWM 占空比信号。</li></ul><hr><h2 id="_2-算能-sophigo-duo-控制核心引脚映射" tabindex="-1">2. 算能 SophiGo Duo 控制核心引脚映射 <a class="header-anchor" href="#_2-算能-sophigo-duo-控制核心引脚映射" aria-label="Permalink to &quot;2. 算能 SophiGo Duo 控制核心引脚映射&quot;">​</a></h2><p>SophiGo Duo 开发板（基于 C906 RISC-V 架构）在我们的底盘（Sophicar）方案中担任核心底盘控制板，通过多路硬定时器捕获编码器脉冲，并生成 PWM 驱动信号。</p><h3 id="_2-1-外设引脚定义示例" tabindex="-1">2.1 外设引脚定义示例 <a class="header-anchor" href="#_2-1-外设引脚定义示例" aria-label="Permalink to &quot;2.1 外设引脚定义示例&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">引脚编号</th><th style="text-align:left;">主控引脚分配</th><th style="text-align:left;">硬件外设功能</th><th style="text-align:left;">连接元器件说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Pin 1</strong></td><td style="text-align:left;"><code>PWM_A1</code></td><td style="text-align:left;">PWM 硬件输出</td><td style="text-align:left;">左电机前行 H 桥通道 A-IN1</td></tr><tr><td style="text-align:left;"><strong>Pin 2</strong></td><td style="text-align:left;"><code>PWM_A2</code></td><td style="text-align:left;">PWM 硬件输出</td><td style="text-align:left;">左电机后退 H 桥通道 A-IN2</td></tr><tr><td style="text-align:left;"><strong>Pin 14</strong></td><td style="text-align:left;"><code>ENC_L_A</code></td><td style="text-align:left;">Timer 捕获 A相</td><td style="text-align:left;">左电机增量式霍尔编码器 A 相</td></tr><tr><td style="text-align:left;"><strong>Pin 15</strong></td><td style="text-align:left;"><code>ENC_L_B</code></td><td style="text-align:left;">Timer 捕获 B相</td><td style="text-align:left;">左电机增量式霍尔编码器 B 相</td></tr><tr><td style="text-align:left;"><strong>Pin 28</strong></td><td style="text-align:left;"><code>UART_TX</code></td><td style="text-align:left;">串口发送端</td><td style="text-align:left;">物理串口总线发送，接树莓派/上位机 RX</td></tr><tr><td style="text-align:left;"><strong>Pin 29</strong></td><td style="text-align:left;"><code>UART_RX</code></td><td style="text-align:left;">串口接收端</td><td style="text-align:left;">物理串口总线接收，接树莓派/上位机 TX</td></tr></tbody></table><hr><h2 id="_3-电机驱动板硬件设计要点" tabindex="-1">3. 电机驱动板硬件设计要点 <a class="header-anchor" href="#_3-电机驱动板硬件设计要点" aria-label="Permalink to &quot;3. 电机驱动板硬件设计要点&quot;">​</a></h2><ol><li><strong>防光耦隔离</strong>: 强电（电机动力电池，如 12V）与弱电控制系统（Duo，5V/3.3V）通过光耦隔离，防止电机反向电动势击穿芯片。</li><li><strong>电流检测</strong>: 在 H 桥下桥臂接入毫欧级采样电阻（Shunt Resistor），利用 Duo 的 ADC 引脚监测电机运行电流，防止电机堵转烧毁。</li><li><strong>稳压系统</strong>: 12V 动力电池经由 DC-DC Buck 降压芯片（如 MP2307 或 LM2596）稳压至 5V 供给上位机和算能 Duo 主板。</li></ol><hr><h2 id="_4-实验课-电机-pid-控制参数校准" tabindex="-1">4. 实验课：电机 PID 控制参数校准 <a class="header-anchor" href="#_4-实验课-电机-pid-控制参数校准" aria-label="Permalink to &quot;4. 实验课：电机 PID 控制参数校准&quot;">​</a></h2><ol><li><strong>P 参数调节</strong>: 从零开始调大比例系数 $K_p$，直到轮子在给定速度时发生轻微振动，再乘以 $0.6$ 回退。</li><li><strong>I 参数调节</strong>: 增加积分系数 $K_i$，用于消除系统稳态误差，缩短静差调节时间。</li><li><strong>D 参数调节</strong>: 视载荷和摩擦力情况微调微分系数 $K_d$，用于抑制车身瞬间加速时的超调。</li></ol>`,22)])])}const _=e(n,[["render",o]]);export{c as __pageData,_ as default};
